import numpy as np

def minimax_with_learned_value(node, children, terminal_values, features, weights, depth, maximizing):
    # Terminal node: return exact value regardless of depth
    if node in terminal_values:
        return float(terminal_values[node])

    # Get children for this node
    node_children = children.get(node, [])

    # Leaf evaluation: depth exhausted or no children
    if depth == 0 or len(node_children) == 0:
        return float(np.dot(features[node], weights))

    # Recursive minimax
    if maximizing:
        best = float('-inf')
        for child in node_children:
            val = minimax_with_learned_value(
                child, children, terminal_values, features, weights, depth - 1, False
            )
            best = max(best, val)
        return best
    else:
        best = float('inf')
        for child in node_children:
            val = minimax_with_learned_value(
                child, children, terminal_values, features, weights, depth - 1, True
            )
            best = min(best, val)
        return best

