import numpy as np

def minimax_with_learned_value(node, children, terminal_values, features, weights, depth, maximizing):
    """
    NumPy version: vectorized leaf evaluation using precomputed value cache.
    For batch scenarios, we precompute all leaf values at once.
    """
    # Precompute all node values using vectorized dot product
    # V = features @ weights  -> shape (num_nodes,)
    all_values = features @ weights  # vectorized for all nodes

    def _minimax(node, depth, maximizing):
        # Terminal: exact value
        if node in terminal_values:
            return float(terminal_values[node])

        node_children = children.get(node, [])

        # Leaf: use precomputed learned value
        if depth == 0 or len(node_children) == 0:
            return float(all_values[node])

        child_values = np.array([
            _minimax(child, depth - 1, not maximizing)
            for child in node_children
        ])

        return float(np.max(child_values) if maximizing else np.min(child_values))

    return _minimax(node, depth, maximizing)
